SELECT [Sales Line].[Document Type], [Sales Line].Type, [Sales Line].No_, Val([quantity]) AS AssortmentQuantity, [Sales Line].[Unit of Measure], [Sales Line].[Constant Variable Code], [Sales Line].[Assortment Code], Val([No_ of Pairs]) AS PairsQuantity, [Salesperson_Purchaser].Name AS Salesperson, [Sales Line].[Delete Reason], [Sales Line].[Customer Price Group], Val([Average Unit Price]) AS GrossUnitPrice, Val([average unit price])*Val([no_ of pairs]) AS GrossLineAmount, Val([line Amount]) AS LineAmount, Val([line amount])-Val([invoice discount value])/100*Val([line amount]) AS NetAmount, Val([Line Discount %]) AS LineDiscountPercentage, Val([Line Discount Amount]) AS LineDiscountAmount, [Sales Header].[Invoice Discount Calculation], Val([Invoice Discount Value]) AS InvoiceDiscountValue, Val([invoice discount value])/100*Val([line amount]) AS InvoiceDiscountAmountCalculated, (Val([line amount])-Val([invoice discount value])/100*Val([line amount]))/Val([no_ of pairs]) AS NetPrice, [Item].[Trademark Code], [Item].[Collection Code], [Item].[Season Code], [Item].[Line Code]
FROM ((([Sales Line] INNER JOIN [Sales Header] ON ([Sales Line].[Document Type]=[Sales Header].[Document Type]) AND ([Sales Line].[Document No_]=[Sales Header].No_)) LEFT JOIN Salesperson_Purchaser ON [Sales Header].[Salesperson Code]=[Salesperson_Purchaser].Code) INNER JOIN [Variable Code] ON ([Sales Line].[Constant Assortment Var_Grp_]=[Variable Code].[Variable Group]) AND ([Sales Line].[Constant Variable Code]=[Variable Code].[Variable Code])) INNER JOIN Item ON [Sales Line].No_=[Item].No_
WHERE ((([Sales Line].Type)=20) AND (([Sales Line].[Delete Reason])=''));

